            Summary = "A guided tour of the Dashboard: widgets, task list, jobs by stage, open orders, cycle progress, and layout customization.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/dashboard"]""",
            Tags = """["dashboard","walkthrough"]""",
            ContentJson = """{"appRoute":"/dashboard","startButtonLabel":"Tour Dashboard","steps":[{"element":".dashboard-content","popover":{"title":"Dashboard Content Area","description":"Your dashboard is built from draggable widgets. Grab any widget by its header and drag it to a new position. Your layout is saved automatically to your user preferences — it'll look the same next time you log in, even from a different device.","side":"top"}},{"element":".dashboard-kpis","popover":{"title":"KPI Overview","description":"Key performance indicators displayed as compact chips at the top of the dashboard. Shows your active job count, overdue count, and total hours for a quick status check. These chips appear when the jobs module is enabled.","side":"bottom"}},{"element":"app-page-header","popover":{"title":"Page Header & Controls","description":"The dashboard header with edit and ambient mode controls. Use these to customize your widget layout or toggle the ambient dashboard display.","side":"bottom"}},{"element":"app-dashboard-widget","popover":{"title":"Dashboard Widget","description":"Each widget in the grid shows a different piece of information — tasks, jobs by stage, open orders, cycle progress, or your end-of-day prompt. Widget order is customizable by dragging. Widgets update in real time as work moves through the board.","side":"right"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Dashboard Field Reference",
            Slug = "dashboard-field-reference",
            Summary = "Complete reference for every widget, indicator, action, and behavior on the Dashboard.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/dashboard"]""",
            Tags = """["dashboard","reference"]""",
            ContentJson = """{"title":"Dashboard Field Reference","groups":[{"heading":"Today's Tasks Widget","items":[{"label":"Job List","value":"Shows your assigned jobs ordered by status — overdue first, then active, upcoming, and completed. Each row displays the job title, job number, assignee avatar, and a status badge."},{"label":"Overdue Highlight","value":"Jobs past their due date are highlighted with a red/error color so they stand out from upcoming tasks."},{"label":"Click Action","value":"Click any job row to open the job detail dialog. From there you can view subtasks, files, activity, and take actions."},{"label":"Empty State","value":"When you have no assigned tasks, the widget shows an empty state message with an icon."}]},{"heading":"End of Day Widget","items":[{"label":"Top 3 Prompt","value":"A textarea prompting you to capture your Top 3 priorities for tomorrow. Type your priorities and save them at the end of your day."},{"label":"Save Button","value":"Saves your end-of-day response. Once saved, the widget switches to a confirmation view showing what you entered."},{"label":"Saved State","value":"After saving, the widget shows your recorded response with a check icon and an Edit button to revise it."},{"label":"Edit Action","value":"Click Edit on the saved view to return to the textarea and update your Top 3 for tomorrow."}]},{"heading":"Open Orders Widget","items":[{"label":"Total Count","value":"Shows the total number of open sales orders as a single headline number."},{"label":"Stage Breakdown","value":"Breaks the open orders down by Confirmed, In Production, and Partially Shipped counts, giving a pipeline overview."},{"label":"View All Link","value":"A 'View all orders' link navigates to the Sales Orders page for the full list."}]},{"heading":"Cycle Progress Widget","items":[{"label":"Progress Bar","value":"Horizontal bar showing the percentage of current planning cycle entries completed."},{"label":"Overdue Status","value":"A status chip shows the days remaining in the cycle, switching to an 'Overdue' label when the cycle has run past its end date."},{"label":"Progress Label","value":"Shows completed vs total entries with the exact completion percentage, e.g. '3/8 (38%)'."},{"label":"Entry List & Link","value":"Lists the first few cycle entries with completion checkmarks; the cycle name and a 'more' link navigate to the Planning page for full detail."}]},{"heading":"Jobs by Stage Widget","items":[{"label":"Stage Bars","value":"A horizontal bar per board stage, with the bar length scaled to each stage's job count relative to the busiest stage."},{"label":"Stage Counts","value":"Each row shows the stage label and the number of jobs currently sitting in that stage."},{"label":"At-a-Glance Pipeline","value":"Lets you see where work is concentrated across the board without opening the Kanban view."}]},{"heading":"Getting Started Banner","items":[{"label":"Onboarding Checklist","value":"Tracks setup progress with steps like create your first job, add a customer, set up track types, receive first stock, and explore reports. Steps are filtered to the capabilities your install has enabled."},{"label":"Dismiss Behavior","value":"The banner hides automatically once enough steps are complete, and can also be dismissed manually with the close button (the dismissal is saved to your preferences)."}]},{"heading":"Team Load Widget","items":[{"label":"Member Rows","value":"One row per team member with their avatar and name, showing how work is distributed across the team."},{"label":"Workload Bar","value":"A horizontal bar per member filled in proportion to their task count against their capacity."},{"label":"Task Count","value":"A numeric count of the member's current tasks shown alongside the bar."}]},{"heading":"KPI Chips","items":[{"label":"Metrics Displayed","value":"A fixed strip of chips at the top of the dashboard showing your active job count, overdue count, and total hours, each with a trend change indicator."},{"label":"Visual Style","value":"Small chips using the KpiChipComponent. Each shows a value, label, and change direction; the overdue chip uses the warn color. The strip appears only when the jobs module is enabled."}]},{"heading":"Layout and Preferences","items":[{"label":"Drag to Rearrange","value":"Grab any widget by its header and drag to reposition. The grid snaps widgets into place."},{"label":"Layout Persistence","value":"Your widget arrangement is saved to user preferences (localStorage + API). Restored on login from any device."},{"label":"Grid System","value":"Powered by gridstack. Widgets have default sizes but can be rearranged freely within the grid."}]},{"heading":"Loading Behavior","items":[{"label":"Initial Load","value":"Dashboard uses LoadingService global overlay while fetching data from multiple endpoints. The overlay clears once all widget data is ready."},{"label":"No Partial Loading","value":"All widgets load together behind the overlay — you see the complete dashboard at once, no flickering or progressive rendering."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Dashboard Knowledge Check",
