            AppRoutes = """["/dashboard"]""",
            Tags = """["dashboard","widgets","catalog","reference"]""",
            ContentJson = """{"title":"Dashboard Widgets Catalog","groups":[{"heading":"Operational Widgets (Jobs module)","items":[{"label":"Today's Tasks","value":"Your assigned jobs ordered by status — overdue first, then active, upcoming, completed. Overdue rows are red. Click a row to open the job detail dialog. 'View board' links to the Kanban. Requires the Jobs/Kanban module."},{"label":"Jobs by Stage","value":"A horizontal bar per board stage, each bar's length scaled to that stage's job count relative to the busiest stage, with the count shown numerically. See where work is concentrated without opening the board. Requires the Jobs/Kanban module."},{"label":"Team Load","value":"One row per team member with avatar, name, a workload bar proportional to their task count vs. capacity, and a numeric task count. Shows how work is distributed. 'Time tracking' link. Requires the Jobs/Kanban module."},{"label":"Deadlines","value":"Upcoming due dates with job number, description, and date; overdue items are flagged. 'View calendar' link. Requires the Jobs/Kanban module."}]},{"heading":"Pipeline & Planning Widgets","items":[{"label":"Open Orders","value":"Total open sales orders as a headline number, broken down by Confirmed, In Production, and Partially Shipped. 'All orders' links to Sales Orders. Requires the Sales Orders module."},{"label":"Cycle Progress","value":"Current planning cycle completion: a progress bar, completed-vs-total entries with percentage, a days-remaining / Overdue status chip, and the first few cycle entries with checkmarks. 'Planning cycles' link. Requires the Planning/MRP module."},{"label":"Margin Summary","value":"Average margin percentage plus revenue, cost, and margin totals for recent jobs. Standalone-accounting only — appears when the built-in accounting module is enabled."}]},{"heading":"Personal & Follow-up Widgets","items":[{"label":"End of Day","value":"A prompt to capture your Top 3 priorities for tomorrow. Type them into the textarea and Save; the widget then shows your saved note with an Edit button. Saved per day to your preferences. Requires the Time Tracking module."},{"label":"Action Items","value":"Follow-up tasks the system raises (quote expiring, lead stale, invoice past due, delivery at risk, maintenance due, QC failure, return received, and more). Each row links to its source record, shows a due date (overdue flagged), and has a check button to complete and a close button to dismiss. Empty state when there's nothing to act on."},{"label":"Activity","value":"A recent activity feed across the system. Always available (no module gate)."}]},{"heading":"Inventory Widget","items":[{"label":"Inventory Snapshot","value":"Part count, total on-hand, and a low-stock count that highlights in alert color when parts fall to or below their minimum threshold; affected parts are listed with current vs. minimum quantities. 'View inventory' link. This is the lead widget on an inventory-only install. Requires the Inventory module."}]},{"heading":"How Widget Availability Works","items":[{"label":"Capability gating","value":"Each widget is tied to a module (capability). A widget only appears on your dashboard — and in the Add Widget menu — if that module is enabled for your install. An inventory-only install sees the Inventory Snapshot instead of the job KPI chips."},{"label":"Add a hidden widget","value":"Turn on Customize (edit mode), open the Add Widget menu, and pick any enabled widget not already on your dashboard."},{"label":"Default layout","value":"New dashboards start with the full enabled widget set in a default arrangement. The Reset button (edit mode) restores this at any time."}]},{"heading":"Widget Frame Controls","items":[{"label":"Title & icon","value":"Every widget renders inside a shared frame with its title and icon at the top."},{"label":"View-all link","value":"Widgets that summarize a larger surface show a link in their header (e.g. 'View board', 'All orders', 'Planning cycles', 'View inventory') that jumps to the full feature."},{"label":"Remove (X)","value":"Visible only in edit mode — removes the widget from your dashboard. Re-add it later from the Add Widget menu."},{"label":"Empty states","value":"Widgets with no data show a friendly empty state (icon + message) rather than a blank card — e.g. Today's Tasks with no assignments, or Action Items with nothing outstanding."}]}]}"""
        });

